// Determine seasonal context and week number
const now = new Date();
const month = now.getMonth() + 1; // 1-12
const day = now.getDate();

// Academic calendar
let academic_season = 'term_time';
if (month >= 6 && month <= 8) academic_season = 'summer_break';
else if (month === 9) academic_season = 'autumn_start';
else if (month === 1) academic_season = 'new_year_start';
else if (month === 12 && day > 15) academic_season = 'winter_break';

// Corporate calendar
let corporate_season = 'normal';
if (month === 1) corporate_season = 'new_year_planning';
else if (month === 3 || month === 4) corporate_season = 'end_of_fiscal_year';
else if (month === 9) corporate_season = 'q4_planning';
else if (month === 12) corporate_season = 'year_end_review';

// Special events
const special_events = [];
if (month === 1 && day >= 20 && day <= 31) special_events.push('National Apprenticeship Week (late Jan)');
if (month === 2 && day >= 6 && day <= 12) special_events.push('National Apprenticeship Week');
if (month === 3 && day === 8) special_events.push('International Womens Day');
if (month === 5 && day >= 15 && day <= 21) special_events.push('Mental Health Awareness Week');
if (month === 6) special_events.push('CIPD Festival of Work (June)');
if (month === 9) special_events.push('CIPD Annual Conference (autumn)');
if (month === 10 && day >= 1 && day <= 7) special_events.push('World Teachers Day');
if (month === 11) special_events.push('CIPD People Management Awards');

// ISO week number
const jan4 = new Date(now.getFullYear(), 0, 4);
const weekNum = Math.ceil(((now - jan4) / 86400000 + jan4.getDay() + 1) / 7);
const year = now.getFullYear();

// Get recent content from previous node
const recentContent = $input.all().map(item => item.json);

return [{
  json: {
    academic_season,
    corporate_season,
    special_events,
    week_number: weekNum,
    year: year,
    current_month: month,
    recent_content: recentContent
  }
}];

// Parse Claude response into individual topics
const response = $input.first().json;
let content = '';
if (response.content && response.content[0]) {
  content = response.content[0].text;
}

// Extract JSON array from response
let topics = [];
try {
  // Try to find JSON array in response
  const match = content.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (match) {
    topics = JSON.parse(match[0]);
  } else {
    topics = JSON.parse(content);
  }
} catch (e) {
  // Fallback: create default topics
  topics = [
    {
      topic_title: "Why UK organisations are rethinking their L&D strategy in " + new Date().getFullYear(),
      content_pillar: "uk_ld_trends",
      target_audience: "corporate",
      topic_angle: "Examining the shift from training delivery to strategic learning partnerships in UK organisations.",
      suggested_post_day: "Tuesday",
      suggested_post_time: "07:30"
    },
    {
      topic_title: "What my PhD taught me about evidence-based learning design",
      content_pillar: "research_practice",
      target_audience: "both",
      topic_angle: "Bridging the gap between academic research and practical L&D implementation.",
      suggested_post_day: "Wednesday",
      suggested_post_time: "12:00"
    },
    {
      topic_title: "AI tools that actually help L&D professionals (not just hype)",
      content_pillar: "digital_ai",
      target_audience: "corporate",
      topic_angle: "Practical AI applications in corporate learning, tested in real programmes.",
      suggested_post_day: "Thursday",
      suggested_post_time: "07:30"
    }
  ];
}

// Get context from earlier nodes
const seasonCtx = $('Seasonal Context').first().json;
const hashtags = $('Load Hashtags').all().map(i => i.json);
const engagement = $('Load Engagement Analytics').all().map(i => i.json);

return topics.map(topic => ({
  json: {
    ...topic,
    week_number: seasonCtx.week_number,
    year: seasonCtx.year,
    academic_season: seasonCtx.academic_season,
    corporate_season: seasonCtx.corporate_season,
    hashtags_library: hashtags,
    engagement_data: engagement
  }
}));

// Get humanized text
const response = $json;
let draftText = '';
if (response.content && response.content[0]) {
  draftText = response.content[0].text;
}

// Get topic info from the loop
const topic = $('Loop Topics').first().json;

// Select hashtags based on content pillar
const hashtagLib = topic.hashtags_library || [];
const pillarToCategories = {
  'uk_ld_trends': ['primary_ld', 'uk_specific', 'hr_people'],
  'leadership_dev': ['leadership', 'primary_ld', 'hr_people'],
  'research_practice': ['academic', 'primary_ld', 'niche_ld'],
  'digital_ai': ['ai_tech', 'primary_ld', 'broad_professional'],
  'international': ['broad_professional', 'primary_ld', 'leadership'],
  'professional_reflections': ['broad_professional', 'primary_ld', 'uk_specific']
};
const targetCategories = pillarToCategories[topic.content_pillar] || ['primary_ld', 'broad_professional'];

// Pick 3-5 hashtags
const selected = [];
for (const cat of targetCategories) {
  const matching = hashtagLib.filter(h => h.category === cat);
  if (matching.length > 0) {
    selected.push(matching[0].hashtag);
  }
  if (selected.length >= 4) break;
}
// Always add one broad hashtag
if (!selected.includes('#LearningAndDevelopment')) {
  selected.push('#LearningAndDevelopment');
}

// Word count
const wordCount = draftText.split(/\s+/).length;

return [{
  json: {
    topic_title: topic.topic_title,
    content_pillar: topic.content_pillar,
    target_audience: topic.target_audience,
    topic_angle: topic.topic_angle,
    draft_text: draftText,
    hashtags: JSON.stringify(selected),
    suggested_post_day: topic.suggested_post_day,
    suggested_post_time: topic.suggested_post_time,
    week_number: topic.week_number,
    year: topic.year,
    word_count: wordCount,
    content_format: 'text_post',
    model_used: 'claude-sonnet-4',
    status: 'drafted'
  }
}];

// Collect all drafts created in this run
// We need to query the DB for this week's drafts
return [{ json: { done: true } }];

const drafts = $input.all().map(i => i.json);
const now = new Date();
const weekStart = new Date(now);
weekStart.setDate(now.getDate() - now.getDay() + 1);
const weekStr = weekStart.toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' });

let html = '<div style="font-family: Georgia, serif; max-width: 600px; margin: 0 auto; color: #333;">';
html += '<h1 style="color: #1a5276; border-bottom: 2px solid #1a5276; padding-bottom: 10px;">LinkedIn Content Drafts Ready</h1>';
html += '<p style="color: #666;">Week of ' + weekStr + ' | ' + drafts.length + ' posts generated</p>';

for (const draft of drafts) {
  html += '<div style="background: #f8f9fa; border-left: 4px solid #2e86c1; padding: 15px; margin: 15px 0; border-radius: 4px;">';
  html += '<h3 style="margin: 0 0 8px 0; color: #1a5276;">' + (draft.topic_title || 'Untitled') + '</h3>';
  html += '<p style="margin: 4px 0; font-size: 13px; color: #666;">';
  html += '<strong>Pillar:</strong> ' + (draft.content_pillar || '').replace(/_/g, ' ') + ' | ';
  html += '<strong>Audience:</strong> ' + (draft.target_audience || '') + ' | ';
  html += '<strong>Day:</strong> ' + (draft.suggested_post_day || '') + ' ' + (draft.suggested_post_time || '') + '</p>';
  html += '<p style="margin: 8px 0; font-style: italic; color: #555;">' + (draft.topic_angle || '') + '</p>';
  html += '<p style="margin: 8px 0;">' + (draft.preview || '').substring(0, 150) + '...</p>';
  html += '<p style="margin: 4px 0; font-size: 12px; color: #888;">~' + (draft.word_count || 0) + ' words</p>';
  html += '</div>';
}

html += '<div style="background: #eaf2f8; padding: 12px; margin-top: 20px; border-radius: 4px;">';
html += '<p style="margin: 0; font-size: 13px;"><strong>Next steps:</strong> Review each draft, add your personal voice, and post on the suggested days.</p>';
html += '</div></div>';

return [{
  json: {
    subject: 'LinkedIn Content Drafts - Week of ' + weekStr,
    html: html
  }
}];

